import axios from 'axios';

const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const api = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    'Content-Type': 'application/json',
  },
});

// Students API
export const studentAPI = {
  getAll: () => api.get('/students'),
  getById: (id) => api.get(`/students/${id}`),
  add: (student) => api.post('/students/add', student),
  addBulk: (students) => api.post('/students/bulk', { students }),
  update: (id, student) => api.put(`/students/${id}`, student),
  delete: (id) => api.delete(`/students/${id}`),
};

// Subjects API
export const subjectAPI = {
  getAll: () => api.get('/subjects'),
  getById: (code) => api.get(`/subjects/${code}`),
  add: (subject) => api.post('/subjects/add', subject),
  addBulk: (subjects) => api.post('/subjects/bulk', { subjects }),
  update: (code, subject) => api.put(`/subjects/${code}`, subject),
  delete: (code) => api.delete(`/subjects/${code}`),
};

// Halls API
export const hallAPI = {
  getAll: () => api.get('/halls'),
  getById: (id) => api.get(`/halls/${id}`),
  add: (hall) => api.post('/halls/add', hall),
  addBulk: (halls) => api.post('/halls/bulk', { halls }),
  update: (id, hall) => api.put(`/halls/${id}`, hall),
  delete: (id) => api.delete(`/halls/${id}`),
};

// Teachers API
export const teacherAPI = {
  getAll: () => api.get('/teachers'),
  getById: (id) => api.get(`/teachers/${id}`),
  add: (teacher) => api.post('/teachers/add', teacher),
  addBulk: (teachers) => api.post('/teachers/bulk', { teachers }),
  update: (id, teacher) => api.put(`/teachers/${id}`, teacher),
  delete: (id) => api.delete(`/teachers/${id}`),
};

// Schedule API
export const scheduleAPI = {
  generate: (data) => api.post('/schedule/generate', data),
  getAll: () => api.get('/schedule/all'),
  getByDate: (date) => api.get(`/schedule/date/${date}`),
  getByDepartment: (dept) => api.get(`/schedule/department/${dept}`),
  getBySemester: (sem) => api.get(`/schedule/semester/${sem}`),
  getStats: () => api.get('/schedule/stats'),
  clear: () => api.delete('/schedule/clear'),
};

export default api;
